 1	import type { FC } from 'react';
 2	
 3	import LabelsList from '@components/NodeSelectorModal/LabelList';
 4	import { GridItem, Text, TextVariants } from '@patternfly/react-core';
 5	import { isEmpty } from '@utils/helpers';
 6	import { useForkliftTranslation } from '@utils/i18n';
 7	
 8	import type { AffinityLabel } from './utils/types';
 9	import AffinityEditRow from './AffinityEditRow';
10	
11	type AffinityEditListProps = {
12	  addRowText: string;
13	  expressions: AffinityLabel[];
14	  onAdd: () => void;
15	  onChange: (aff: AffinityLabel) => void;
16	  onDelete: (id: number) => void;
17	  testId?: string;
18	};
19	
20	const AffinityEditList: FC<AffinityEditListProps> = ({
21	  addRowText,
22	  expressions,
23	  onAdd,
24	  onChange,
25	  onDelete,
26	  testId,
27	}) => {
28	  const { t } = useForkliftTranslation();
29	
30	  return (
31	    <LabelsList
32	      addRowText={addRowText}
33	      emptyStateAddRowText={addRowText}
34	      isEmpty={isEmpty(expressions)}
35	      onLabelAdd={onAdd}
36	      testId={testId}
37	    >
38	      {!isEmpty(expressions) && (
39	        <>
40	          <GridItem span={4}>
41	            <Text component={TextVariants.h6}>{t('Key')}</Text>
42	          </GridItem>
43	          <GridItem span={2}>
44	            <Text component={TextVariants.h6}>{t('Operator')}</Text>
45	          </GridItem>
46	          <GridItem span={6}>
47	            <Text component={TextVariants.h6}>{t('Values')}</Text>
48	          </GridItem>
49	          {expressions.map((expression) => (
50	            <AffinityEditRow
51	              expression={expression}
52	              key={expression.id}
53	              onChange={onChange}
54	              onDelete={onDelete}
55	            />
56	          ))}
57	        </>
58	      )}
59	    </LabelsList>
60	  );
61	};
62	
63	export default AffinityEditList;

